#define BLOCK_SIZE 16

#define AA(_i, _j) a[offset * size + _i * size + _j + offset]
#define BB(_i, _j) a[_i * size + _j]

__kernel void lud_diagonal(__global float* a, __local float* local_mem, int size, int offset) {
    int i = get_global_id(0);
    int j, k;

    if (i >= BLOCK_SIZE) return;

    // Load diagonal block into local memory if needed, or operate directly
    // The original code operates directly on global memory with AA macro
    // We will replicate the logic directly

    for (j = i; j < BLOCK_SIZE; j++) {
        float sum = 0.0f;
        for (k = 0; k < i; k++) {
            sum += AA(i, k) * AA(k, j);
        }
        AA(i, j) = AA(i, j) - sum;
    }

    float temp = 1.0f / AA(i, i);

    for (j = i + 1; j < BLOCK_SIZE; j++) {
        float sum = 0.0f;
        for (k = 0; k < i; k++) {
            sum += AA(j, k) * AA(k, i);
        }
        AA(j, i) = (AA(j, i) - sum) * temp;
    }
}

__kernel void lud_perimeter(__global float* a, __local float* temp_top, __local float* temp_left, __local float* temp_div, int size, int offset) {
    int idx = get_global_id(0);
    int total_chunks = (size - offset - BLOCK_SIZE) / BLOCK_SIZE;

    if (idx >= total_chunks * 2) return;

    int i, j, k;
    int i_global, j_global;
    float sum;

    if (idx < total_chunks) {
        // Right perimeter: Update blocks to the right of the diagonal block
        int chunk_idx = idx;
        int row = 0; // We are processing the rows inside the diagonal block (0 to BLOCK_SIZE-1)

        // Load temp row from diagonal block (row 'row' of the diagonal block)
        // This needs to be done for each row in the diagonal block. 
        // However, the kernel structure in OMP iterates chunk_idx then does all rows.
        // To map to OpenCL efficiently, we might need a different strategy or just replicate the loop structure.
        // Given the constraint to preserve algorithm, let's try to map the outer loop to threads.
        // The OMP code: for chunk_idx ... { for i=0..BS ... }
        // We can make global_id correspond to (chunk_idx, i) or just chunk_idx and loop i inside.
        // Let's stick to chunk_idx as global_id and loop i inside to match the source structure closely.

        int j_global_base = offset + BLOCK_SIZE * (chunk_idx + 1);

        for (i = 0; i < BLOCK_SIZE; i++) {
            // Load row i of the diagonal block into local/temp variable
            // Since we can't easily share across threads without complex sync, and original code loads per chunk_idx
            // We will just read from global memory repeatedly or use local if we restructure.
            // Original OMP code loads a row into temp[BS*BS] (actually just a row effectively used).
            // Let's optimize slightly by loading the necessary row into a local array for this thread.
            float temp_row[BLOCK_SIZE];
            for (j = 0; j < BLOCK_SIZE; j++) {
                temp_row[j] = a[size * (i + offset) + offset + j];
            }

            j_global = j_global_base;
            for (j = 0; j < BLOCK_SIZE; j++) {
                sum = 0.0f;
                for (k = 0; k < i; k++) {
                    sum += temp_row[k] * BB(i + offset, j_global + j);
                }
                BB(i + offset, j_global + j) -= sum;
            }
        }
    } else {
        // Bottom perimeter: Update blocks below the diagonal block
        int chunk_idx = idx - total_chunks;
        int col = 0; // Processing columns inside the diagonal block

        int i_global_base = offset + BLOCK_SIZE * (chunk_idx + 1);

        for (j = 0; j < BLOCK_SIZE; j++) {
            // Load column j of the diagonal block
            float temp_col[BLOCK_SIZE];
            for (i = 0; i < BLOCK_SIZE; i++) {
                temp_col[i] = BB(i + offset, j + offset);
            }

            // Also need the diagonal element for division: a[size*(offset+j) + offset+j]
            float diag_elem = BB(j + offset, j + offset);

            i_global = i_global_base;
            for (i = 0; i < BLOCK_SIZE; i++) {
                sum = 0.0f;
                for (k = 0; k < j; k++) {
                    sum += BB(i_global + i, k + offset) * temp_col[k];
                }
                int idx_global = size * (i_global + i) + (j + offset);
                a[idx_global] = (a[idx_global] - sum) / diag_elem;
            }
        }
    }
}

__kernel void lud_internal(__global float* a, __local float* temp_top, __local float* temp_left, int size, int offset) {
    int gx = get_global_id(0);
    int gy = get_global_id(1);

    int chunks_in_row = (size - offset - BLOCK_SIZE) / BLOCK_SIZE;

    if (gx >= chunks_in_row || gy >= chunks_in_row) return;

    int i_global = offset + BLOCK_SIZE * (1 + gy);
    int j_global = offset + BLOCK_SIZE * (1 + gx);

    int i, j, k;

    // Load top block (from diagonal block row) into local memory
    // The block above the current block is at row (offset) to (offset+BS), col (j_global) to (j_global+BS)
    for (i = 0; i < BLOCK_SIZE; i++) {
        for (j = 0; j < BLOCK_SIZE; j++) {
            temp_top[i * BLOCK_SIZE + j] = a[size * (i + offset) + j_global + j];
        }
    }

    // Load left block (from diagonal block col) into local memory
    // The block to the left of current block is at row (i_global) to (i_global+BS), col (offset) to (offset+BS)
    for (i = 0; i < BLOCK_SIZE; i++) {
        for (j = 0; j < BLOCK_SIZE; j++) {
            temp_left[i * BLOCK_SIZE + j] = a[size * (i_global + i) + offset + j];
        }
    }

    // Perform multiplication and subtraction
    for (i = 0; i < BLOCK_SIZE; i++) {
        for (j = 0; j < BLOCK_SIZE; j++) {
            float sum = 0.0f;
            for (k = 0; k < BLOCK_SIZE; k++) {
                sum += temp_left[i * BLOCK_SIZE + k] * temp_top[k * BLOCK_SIZE + j];
            }
            BB(i_global + i, j_global + j) -= sum;
        }
    }
}
